use std::fmt;

trait ToDisplayable {}

impl<T: fmt::Display> ToDisplayable for T {}

struct DataContainer<T: ToDisplayable> {
    value: T
}

impl<T: ToDisplayable + Copy> Default for DataContainer<T> {
    fn default() -> Self {
        DataContainer { value: unsafe { std::mem::zeroed() } }
    }
}

fn main() {
    let number_value = 42;
    let string_value = "Hello World";

    let container1: DataContainer<i32> = DataContainer { value: number_value };
    let container2: DataContainer<String> = DataContainer { value: string_value.to_string() };

    println!("Number stored: {}", container1.value);
    println!("String stored: {}", container2.value);
}

use std::fmt::{self, Display};
use std::convert::From;

trait MyTrait {
    fn process(&self) -> String;
}

struct FirstType(i32);
impl MyTrait for FirstType {
    fn process(&self) -> String {
        format!("Processing first type: {}", self.0)
    }
}

#[derive(Clone)]
struct SecondType(String);
impl MyTrait for SecondType {
    fn process(&self) -> String {
        format!("Processing second type: {}", &self.0)
    }
}

impl From<FirstType> for SecondType {
    fn from(item: FirstType) -> Self {
        SecondType(format!("Converted from first type value: {}", item.0))
    }
}

fn main() {
    let a = FirstType(42);
    let b = SecondType(String::from("initial data"));

    println!("Result A: {}", a.process());

    let c: SecondType = b.clone().into();
    println!("Result C after conversion: {}", c.process());
}

use std::convert::From;

struct OriginalData(i32);

struct TargetFormat(String);

impl From<OriginalData> for TargetFormat {
    fn from(data: OriginalData) -> Self {
        TargetFormat(format!("Processed {}", data.0))
    }
}

struct AnotherType(f64);

impl From<AnotherType> for TargetFormat {
    fn from(data: AnotherType) -> Self {
        TargetFormat(format!("Calculated based on {}", data.0))
    }
}

fn main() {
    let original = OriginalData(42);
    let target_from_original: TargetFormat = original.into();
    println!("Conversion 1: {}", target_from_original.0);

    let another = AnotherType(3.14);
    let target_from_another: TargetFormat = another.into();
    println!("Conversion 2: {}", target_from_another.0);
}

use std::fmt::{self, Display};

trait Printable {
    fn display_info(&self) -> String;
}

struct IntegerWrapper(i32);

impl Printable for IntegerWrapper {
    fn display_info(&self) -> String {
        format!("The number is: {}", self.0)
    }
}

struct FloatWrapper(f64);

impl Printable for FloatWrapper {
    fn display_info(&self) -> String {
        format!("The value is: {}", self.0)
    }
}

fn process_printable<T: Printable>(item: T) -> String {
    item.display_info()
}

fn main() {
    let int_val = IntegerWrapper(42);
    let float_val = FloatWrapper(3.14159);

    let result1 = process_printable(int_val);
    println!("Result 1: {}", result1);

    let result2 = process_printable(float_val);
    println!("Result 2: {}", result2);
}

use std::fmt::{self, Display};

trait Printable {
    fn display_value(&self) -> String;
}

struct UserID(u64);

impl Printable for UserID {
    fn display_value(&self) -> String {
        format!("User ID: {}", self.0)
    }
}

struct Product(String);

impl Printable for Product {
    fn display_value(&self) -> String {
        format!("Product Name: {}", &self.0)
    }
}

trait FromPrintable<T> {
    fn from_printable(item: T) -> Self;
}

impl<T: Printable + 'static> FromPrintable<T> for String {
    fn from_printable(item: T) -> Self {
        item.display_value()
    }
}

fn main() {
    let id = UserID(1001);
    let product = Product("Laptop".to_string());

    let user_str = String::from_printable(id);
    println!("Converted 1: {}", user_str);

    let product_str = String::from_printable(product);
    println!("Converted 2: {}", product_str);
}
